234: // generatePodSandboxWindowsConfig generates WindowsPodSandboxConfig from v1.Pod.
235: // On Windows this will get called in addition to LinuxPodSandboxConfig because not all relevant fields have been added to
236: // WindowsPodSandboxConfig at this time.
237: func (m *kubeGenericRuntimeManager) generatePodSandboxWindowsConfig(pod *v1.Pod) (*runtimeapi.WindowsPodSandboxConfig, error) {
238: 	wc := &runtimeapi.WindowsPodSandboxConfig{
239: 		SecurityContext: &runtimeapi.WindowsSandboxSecurityContext{},
240: 	}
241: 
242: 	if utilfeature.DefaultFeatureGate.Enabled(features.WindowsHostNetwork) {
243: 		wc.SecurityContext.NamespaceOptions = &runtimeapi.WindowsNamespaceOption{}
244: 		if kubecontainer.IsHostNetworkPod(pod) {
245: 			wc.SecurityContext.NamespaceOptions.Network = runtimeapi.NamespaceMode_NODE
246: 		} else {
247: 			wc.SecurityContext.NamespaceOptions.Network = runtimeapi.NamespaceMode_POD
248: 		}
249: 	}
250: 
251: 	// If all of the containers in a pod are HostProcess containers, set the pod's HostProcess field
252: 	// explicitly because the container runtime requires this information at sandbox creation time.
253: 	if kubecontainer.HasWindowsHostProcessContainer(pod) {
254: 		// At present Windows all containers in a Windows pod must be HostProcess containers
255: 		// and HostNetwork is required to be set.
256: 		if !kubecontainer.AllContainersAreWindowsHostProcess(pod) {
257: 			return nil, fmt.Errorf("pod must not contain both HostProcess and non-HostProcess containers")
258: 		}
259: 
260: 		if !kubecontainer.IsHostNetworkPod(pod) {
261: 			return nil, fmt.Errorf("hostNetwork is required if Pod contains HostProcess containers")
262: 		}
263: 
264: 		wc.SecurityContext.HostProcess = true
265: 	}
266: 
267: 	sc := pod.Spec.SecurityContext
268: 	if sc == nil || sc.WindowsOptions == nil {
269: 		return wc, nil
270: 	}
271: 
272: 	wo := sc.WindowsOptions
273: 	if wo.GMSACredentialSpec != nil {
274: 		wc.SecurityContext.CredentialSpec = *wo.GMSACredentialSpec
275: 	}
276: 
277: 	if wo.RunAsUserName != nil {
278: 		wc.SecurityContext.RunAsUsername = *wo.RunAsUserName
279: 	}
280: 
281: 	if kubecontainer.HasWindowsHostProcessContainer(pod) {
282: 
283: 		if wo.HostProcess != nil && !*wo.HostProcess {
284: 			return nil, fmt.Errorf("pod must not contain any HostProcess containers if Pod's WindowsOptions.HostProcess is set to false")
285: 		}
286: 	}
287: 
288: 	return wc, nil
289: }
