291: // getKubeletSandboxes lists all (or just the running) sandboxes managed by kubelet.
292: func (m *kubeGenericRuntimeManager) getKubeletSandboxes(ctx context.Context, all bool) ([]*runtimeapi.PodSandbox, error) {
293: 	var filter *runtimeapi.PodSandboxFilter
294: 	if !all {
295: 		readyState := runtimeapi.PodSandboxState_SANDBOX_READY
296: 		filter = &runtimeapi.PodSandboxFilter{
297: 			State: &runtimeapi.PodSandboxStateValue{
298: 				State: readyState,
299: 			},
300: 		}
301: 	}
302: 
303: 	resp, err := m.runtimeService.ListPodSandbox(ctx, filter)
304: 	if err != nil {
305: 		klog.ErrorS(err, "Failed to list pod sandboxes")
306: 		return nil, err
307: 	}
308: 
309: 	return resp, nil
310: }
