312: // determinePodSandboxIP determines the IP addresses of the given pod sandbox.
313: func (m *kubeGenericRuntimeManager) determinePodSandboxIPs(podNamespace, podName string, podSandbox *runtimeapi.PodSandboxStatus) []string {
314: 	podIPs := make([]string, 0)
315: 	if podSandbox.Network == nil {
316: 		klog.InfoS("Pod Sandbox status doesn't have network information, cannot report IPs", "pod", klog.KRef(podNamespace, podName))
317: 		return podIPs
318: 	}
319: 
320: 	// ip could be an empty string if runtime is not responsible for the
321: 	// IP (e.g., host networking).
322: 
323: 	// pick primary IP
324: 	if len(podSandbox.Network.Ip) != 0 {
325: 		if netutils.ParseIPSloppy(podSandbox.Network.Ip) == nil {
326: 			klog.InfoS("Pod Sandbox reported an unparseable primary IP", "pod", klog.KRef(podNamespace, podName), "IP", podSandbox.Network.Ip)
327: 			return nil
328: 		}
329: 		podIPs = append(podIPs, podSandbox.Network.Ip)
330: 	}
331: 
332: 	// pick additional ips, if cri reported them
333: 	for _, podIP := range podSandbox.Network.AdditionalIps {
334: 		if nil == netutils.ParseIPSloppy(podIP.Ip) {
335: 			klog.InfoS("Pod Sandbox reported an unparseable additional IP", "pod", klog.KRef(podNamespace, podName), "IP", podIP.Ip)
336: 			return nil
337: 		}
338: 		podIPs = append(podIPs, podIP.Ip)
339: 	}
340: 
341: 	return podIPs
342: }
