344: // getPodSandboxID gets the sandbox id by podUID and returns ([]sandboxID, error).
345: // Param state could be nil in order to get all sandboxes belonging to same pod.
346: func (m *kubeGenericRuntimeManager) getSandboxIDByPodUID(ctx context.Context, podUID kubetypes.UID, state *runtimeapi.PodSandboxState) ([]string, error) {
347: 	filter := &runtimeapi.PodSandboxFilter{
348: 		LabelSelector: map[string]string{types.KubernetesPodUIDLabel: string(podUID)},
349: 	}
350: 	if state != nil {
351: 		filter.State = &runtimeapi.PodSandboxStateValue{
352: 			State: *state,
353: 		}
354: 	}
355: 	sandboxes, err := m.runtimeService.ListPodSandbox(ctx, filter)
356: 	if err != nil {
357: 		klog.ErrorS(err, "Failed to list sandboxes for pod", "podUID", podUID)
358: 		return nil, err
359: 	}
360: 
361: 	if len(sandboxes) == 0 {
362: 		return nil, nil
363: 	}
364: 
365: 	// Sort with newest first.
366: 	sandboxIDs := make([]string, len(sandboxes))
367: 	sort.Sort(podSandboxByCreated(sandboxes))
368: 	for i, s := range sandboxes {
369: 		sandboxIDs[i] = s.Id
370: 	}
371: 
372: 	return sandboxIDs, nil
373: }
