375: // GetPortForward gets the endpoint the runtime will serve the port-forward request from.
376: func (m *kubeGenericRuntimeManager) GetPortForward(ctx context.Context, podName, podNamespace string, podUID kubetypes.UID, ports []int32) (*url.URL, error) {
377: 	sandboxIDs, err := m.getSandboxIDByPodUID(ctx, podUID, nil)
378: 	if err != nil {
379: 		return nil, fmt.Errorf("failed to find sandboxID for pod %s: %v", format.PodDesc(podName, podNamespace, podUID), err)
380: 	}
381: 	if len(sandboxIDs) == 0 {
382: 		return nil, fmt.Errorf("failed to find sandboxID for pod %s", format.PodDesc(podName, podNamespace, podUID))
383: 	}
384: 	req := &runtimeapi.PortForwardRequest{
385: 		PodSandboxId: sandboxIDs[0],
386: 		Port:         ports,
387: 	}
388: 	resp, err := m.runtimeService.PortForward(ctx, req)
389: 	if err != nil {
390: 		return nil, err
391: 	}
392: 	return url.Parse(resp.Url)
393: }
