452: // PodSandboxConfig holds all the required and optional fields for creating a
453: // sandbox.
454: message PodSandboxConfig {
455:     // Metadata of the sandbox. This information will uniquely identify the
456:     // sandbox, and the runtime should leverage this to ensure correct
457:     // operation. The runtime may also use this information to improve UX, such
458:     // as by constructing a readable name.
459:     PodSandboxMetadata metadata = 1;
460:     // Hostname of the sandbox. Hostname could only be empty when the pod
461:     // network namespace is NODE.
462:     string hostname = 2;
463:     // Path to the directory on the host in which container log files are
464:     // stored.
465:     // By default the log of a container going into the LogDirectory will be
466:     // hooked up to STDOUT and STDERR. However, the LogDirectory may contain
467:     // binary log files with structured logging data from the individual
468:     // containers. For example, the files might be newline separated JSON
469:     // structured logs, systemd-journald journal files, gRPC trace files, etc.
470:     // E.g.,
471:     //     PodSandboxConfig.LogDirectory = `/var/log/pods/<NAMESPACE>_<NAME>_<UID>/`
472:     //     ContainerConfig.LogPath = `containerName/Instance#.log`
473:     string log_directory = 3;
474:     // DNS config for the sandbox.
475:     DNSConfig dns_config = 4;
476:     // Port mappings for the sandbox.
477:     repeated PortMapping port_mappings = 5;
478:     // Key-value pairs that may be used to scope and select individual resources.
479:     map<string, string> labels = 6;
480:     // Unstructured key-value map that may be set by the kubelet to store and
481:     // retrieve arbitrary metadata. This will include any annotations set on a
482:     // pod through the Kubernetes API.
483:     //
484:     // Annotations MUST NOT be altered by the runtime; the annotations stored
485:     // here MUST be returned in the PodSandboxStatus associated with the pod
486:     // this PodSandboxConfig creates.
487:     //
488:     // In general, in order to preserve a well-defined interface between the
489:     // kubelet and the container runtime, annotations SHOULD NOT influence
490:     // runtime behaviour.
491:     //
492:     // Annotations can also be useful for runtime authors to experiment with
493:     // new features that are opaque to the Kubernetes APIs (both user-facing
494:     // and the CRI). Whenever possible, however, runtime authors SHOULD
495:     // consider proposing new typed fields for any new features instead.
496:     map<string, string> annotations = 7;
497:     // Optional configurations specific to Linux hosts.
498:     LinuxPodSandboxConfig linux = 8;
499:     // Optional configurations specific to Windows hosts.
500:     WindowsPodSandboxConfig windows = 9;
